#define _USE_MATH_DEFINES
#include <iostream>
#include <cmath>

class Circle {
private:
    double radius;

public:
    Circle(double r) : radius(r) {}
    double getRadius() const {
        return radius;
    }
    double calculateArea() const {
        return M_PI * radius * radius;
    }
};

int main() {
    std::cout.precision(12);
    double r_test;
    while (std::cin >> r_test) {
        Circle c(r_test);
        std::cout << c.calculateArea() << std::endl;
    }
    return 0;
}
